    .rst_ni     (rst_ni),
    .clr_i      (sfifo_observe_clr),
    .wvalid   (sfifo_observe_push),
    .wdata    (sfifo_observe_wdata),
    .wready   (),
    .rvalid   (sfifo_observe_not_empty),
    .rdata    (sfifo_observe_rdata),
    .rready   (sfifo_observe_pop)
  );


  assign sfifo_observe_depth = '0;
