  // send processed entropy to final fifo
  //--------------------------------------------

  prim_fifo_sync #(
    .Width(1+SeedLen),
    .Pass(0),
    .Depth(EsFifoDepth)
  ) u_prim_fifo_sync_esfinal (
    .clk_i          (clk_i),
    .rst_ni         (rst_ni),
    .clr_i          (sfifo_esfinal_clr),
    .wvalid       (sfifo_esfinal_push),
    .wready      (sfifo_esfinal_not_full),
    .wdata        (sfifo_esfinal_wdata),
    .rvalid       (sfifo_esfinal_not_empty),
    .rready       (sfifo_esfinal_pop),
    .rdata       (sfifo_esfinal_rdata)
  );

